def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    avg_capacity = np.mean(bins[bins > 0]) if np.any(bins > 0) else 1
    variance = np.var(bins[bins > 0]) if np.any(bins > 0) else 0.1
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1:
            score = 0.0
        elif ratio > 0.85:
            score = ((1 - ratio) ** 5) * 1.2 + 0.25
        elif 0.6 < ratio <= 0.85:
            score = np.exp(-ratio * 15) + 0.08
        elif 0.3 < ratio <= 0.6:
            temp = 0.0
            for k in range(1, 9):
                term = ((-1) ** (k+1)) * (ratio ** (k + 2)) / (k * 1.1)
                temp += term
            score = abs(temp) + 0.09
        else:
            temp = 0.0
            for p in range(1, 12):
                weight = 1 / (p ** 1.3)
                temp += ((-1) ** p) * (ratio ** (p + 1)) * weight
            score = abs(temp) + 0.11
        neighbors_influence = 0.0
        neighbors_weights_sum = 0.0
        for offset in range(1, 8):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff = abs(capacity - neighbor_capacity)
                    norm_diff = diff / max(capacity, neighbor_capacity)
                    weight = 1 / (offset ** 2)
                    influence = norm_diff * weight
                    if neighbor_capacity > avg_capacity + variance:
                        influence *= 1.1
                    elif neighbor_capacity < avg_capacity - variance:
                        influence *= 0.9
                    neighbors_influence += influence
                    neighbors_weights_sum += weight
        if neighbors_weights_sum > 0:
            neighbors_influence /= neighbors_weights_sum
        cap_factor = (capacity ** 0.7) + (avg_capacity ** 0.3)
        if cap_factor == 0:
            cap_factor = 1
        penalty = 0
        if capacity < item:
            penalty = ((item - capacity) ** 3) * 0.4
        elif capacity > item * 2:
            penalty = 0.05
        if i % 2 == 0 and i % 3 == 0:
            score *= 0.8
            neighbors_influence *= 1.2
            penalty *= 1.1
        elif i % 4 == 0:
            score *= 1.1
            neighbors_influence *= 0.9
        else:
            score *= 0.95
        priority = score + neighbors_influence / cap_factor + penalty
        if priority < 0:
            priority = 0
        priorities[i] = priority
    finite = priorities[np.isfinite(priorities)]
    if finite.size == 0:
        return priorities
    max_finite = np.max(finite)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 6
    return priorities
